// OAuth Configuration
const OAUTH_CONFIG = {
  clientId: process.env.REACT_APP_OAUTH_CLIENT_ID || 'your-client-id',
  clientSecret: process.env.REACT_APP_OAUTH_CLIENT_SECRET || '',
  authorizationEndpoint: process.env.REACT_APP_AUTH_ENDPOINT || 'https://auth.example.com/authorize',
  tokenEndpoint: process.env.REACT_APP_TOKEN_ENDPOINT || 'https://auth.example.com/oauth/token',
  redirectUri: process.env.REACT_APP_REDIRECT_URI || window.location.origin + '/callback',
  scope: process.env.REACT_APP_OAUTH_SCOPE || 'openid profile email',
  apiBaseUrl: process.env.REACT_APP_API_BASE_URL || 'https://api.example.com',
};

// PKCE Utilities
function generateRandomString(length) {
  const charset = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-._~';
  const array = new Uint8Array(length);
  crypto.getRandomValues(array);
  return Array.from(array, (byte) => charset[byte % charset.length]).join('');
}

async function generateCodeChallenge(codeVerifier) {
  const encoder = new TextEncoder();
  const data = encoder.encode(codeVerifier);
  const digest = await crypto.subtle.digest('SHA-256', data);
  return btoa(String.fromCharCode(...new Uint8Array(digest)))
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/, '');
}

// Token Storage Utilities
const TokenStorage = {
  setTokens(tokens) {
    localStorage.setItem('oauth_access_token', tokens.access_token);
    if (tokens.refresh_token) {
      localStorage.setItem('oauth_refresh_token', tokens.refresh_token);
    }
    if (tokens.expires_in) {
      const expiresAt = Date.now() + tokens.expires_in * 1000;
      localStorage.setItem('oauth_expires_at', expiresAt.toString());
    }
    if (tokens.id_token) {
      localStorage.setItem('oauth_id_token', tokens.id_token);
    }
    if (tokens.token_type) {
      localStorage.setItem('oauth_token_type', tokens.token_type);
    }
  },

  getAccessToken() {
    return localStorage.getItem('oauth_access_token');
  },

  getRefreshToken() {
    return localStorage.getItem('oauth_refresh_token');
  },

  getTokenType() {
    return localStorage.getItem('oauth_token_type') || 'Bearer';
  },

  isTokenExpired() {
    const expiresAt = localStorage.getItem('oauth_expires_at');
    if (!expiresAt) return true;
    return Date.now() >= parseInt(expiresAt, 10) - 60000; // 1 minute buffer
  },

  clearTokens() {
    localStorage.removeItem('oauth_access_token');
    localStorage.removeItem('oauth_refresh_token');
    localStorage.removeItem('oauth_expires_at');
    localStorage.removeItem('oauth_id_token');
    localStorage.removeItem('oauth_token_type');
    localStorage.removeItem('oauth_code_verifier');
    localStorage.removeItem('oauth_state');
  },

  setCodeVerifier(verifier) {
    localStorage.setItem('oauth_code_verifier', verifier);
  },

  getCodeVerifier() {
    return localStorage.getItem('oauth_code_verifier');
  },

  setState(state) {
    localStorage.setItem('oauth_state', state);
  },

  getState() {
    return localStorage.getItem('oauth_state');
  },
};

// OAuth Service
const OAuthService = {
  async initiateLogin() {
    const state = generateRandomString(32);
    const codeVerifier = generateRandomString(64);
    const codeChallenge = await generateCodeChallenge(codeVerifier);

    TokenStorage.setState(state);
    TokenStorage.setCodeVerifier(codeVerifier);

    const params = new URLSearchParams({
      response_type: 'code',
      client_id: OAUTH_CONFIG.clientId,
      redirect_uri: OAUTH_CONFIG.redirectUri,
      scope: OAUTH_CONFIG.scope,
      state: state,
      code_challenge: codeChallenge,
      code_challenge_method: 'S256',
    });

    window.location.href = `${OAUTH_CONFIG.authorizationEndpoint}?${params.toString()}`;
  },

  async exchangeCodeForTokens(code) {
    const codeVerifier = TokenStorage.getCodeVerifier();

    if (!codeVerifier) {
      throw new Error('Code verifier not found. Authorization flow may have been tampered with.');
    }

    const body = new URLSearchParams({
      grant_type: 'authorization_code',
      code: code,
      redirect_uri: OAUTH_CONFIG.redirectUri,
      client_id: OAUTH_CONFIG.clientId,
      code_verifier: codeVerifier,
    });

    if (OAUTH_CONFIG.clientSecret) {
      body.append('client_secret', OAUTH_CONFIG.clientSecret);
    }

    const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: body.toString(),
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(
        errorData.error_description || errorData.error || `Token exchange failed: ${response.status}`
      );
    }

    const tokens = await response.json();
    TokenStorage.setTokens(tokens);
    localStorage.removeItem('oauth_code_verifier');
    localStorage.removeItem('oauth_state');

    return tokens;
  },

  async refreshAccessToken() {
    const refreshToken = TokenStorage.getRefreshToken();
    if (!refreshToken) {
      throw new Error('No refresh token available');
    }

    const body = new URLSearchParams({
      grant_type: 'refresh_token',
      refresh_token: refreshToken,
      client_id: OAUTH_CONFIG.clientId,
    });

    if (OAUTH_CONFIG.clientSecret) {
      body.append('client_secret', OAUTH_CONFIG.clientSecret);
    }

    const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: body.toString(),
    });

    if (!response.ok) {
      TokenStorage.clearTokens();
      throw new Error('Token refresh failed');
    }

    const tokens = await response.json();
    TokenStorage.setTokens(tokens);
    return tokens;
  },

  logout() {
    TokenStorage.clearTokens();
    window.location.href = '/';
  },

  isAuthenticated() {
    const token = TokenStorage.getAccessToken();
    return !!token && !TokenStorage.isTokenExpired();
  },
};

// Authenticated Fetch Wrapper
async function authenticatedFetch(url, options = {}) {
  let accessToken = TokenStorage.getAccessToken();

  if (TokenStorage.isTokenExpired()) {
    try {
      await OAuthService.refreshAccessToken();
      accessToken = TokenStorage.getAccessToken();
    } catch (error) {
      OAuthService.logout();
      throw new Error('Session expired. Please log in again.');
    }
  }

  if (!accessToken) {
    throw new Error('No access token available');
  }

  const tokenType = TokenStorage.getTokenType();
  const headers = {
    ...options.headers,
    Authorization: `${tokenType} ${accessToken}`,
  };

  const fullUrl = url.startsWith('http') ? url : `${OAUTH_CONFIG.apiBaseUrl}${url}`;

  let response = await fetch(fullUrl, { ...options, headers });

  if (response.status === 401) {
    try {
      await OAuthService.refreshAccessToken();
      accessToken = TokenStorage.getAccessToken();
      headers.Authorization = `${tokenType} ${accessToken}`;
      response = await fetch(fullUrl, { ...options, headers });
    } catch (refreshError) {
      OAuthService.logout();
      throw new Error('Session expired. Please log in again.');
    }
  }

  return response;
}

// Auth Context
const AuthContext = createContext(null);

function AuthProvider({ children }) {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [user, setUser] = useState(null);
  const [error, setError] = useState(null);

  const fetchUserProfile = useCallback(async () => {
    try {
      const response = await authenticatedFetch('/userinfo');
      if (response.ok) {
        const userData = await response.json();
        setUser(userData);
      }
    } catch (err) {
      console.error('Failed to fetch user profile:', err);
    }
  }, []);

  useEffect(() => {
    const initAuth = async () => {
      if (OAuthService.isAuthenticated()) {
        setIsAuthenticated(true);
        await fetchUserProfile();
      }
      setIsLoading(false);
    };
    initAuth();
  }, [fetchUserProfile]);

  const login = useCallback(async () => {
    setError(null);
    try {
      await OAuthService.initiateLogin();
    } catch (err) {
      setError(err.message);
    }
  }, []);

  const handleCallback = useCallback(
    async (code, state) => {
      setIsLoading(true);
      setError(null);

      try {
        const savedState = TokenStorage.getState();
        if (state !== savedState) {
          throw new Error('State mismatch. Possible CSRF attack detected.');
        }

        await OAuthService.exchangeCodeForTokens(code);
        setIsAuthenticated(true);
        await fetchUserProfile();

        window.history.replaceState({}, document.title, '/dashboard');
      } catch (err) {
        setError(err.message);
        TokenStorage.clearTokens();
      } finally {
        setIsLoading(false);
      }
    },
    [fetchUserProfile]
  );

  const logout = useCallback(() => {
    setUser(null);
    setIsAuthenticated(false);
    OAuthService.logout();
  }, []);

  const value = {
    isAuthenticated,
    isLoading,
    user,
    error,
    login,
    logout,
    handleCallback,
    authenticatedFetch,
  };

  return React.createElement(AuthContext.Provider, { value }, children);
}

function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

// Simple Router
function useRouter() {
  const [path, setPath] = useState(window.location.pathname);
  const [searchParams] = useState(new URLSearchParams(window.location.search));

  useEffect(() => {
    const handlePopState = () => {
      setPath(window.location.pathname);
    };
    window.addEventListener('popstate', handlePopState);
    return () => window.removeEventListener('popstate', handlePopState);
  }, []);

  const navigate = useCallback((newPath) => {
    window.history.pushState({}, '', newPath);
    setPath(newPath);
  }, []);

  return { path, searchParams, navigate };
}

