// Callback Page Component
function CallbackPage() {
  const { handleCallback, error } = useAuth();
  const { searchParams } = useRouter();

  useEffect(() => {
    const code = searchParams.get('code');
    const state = searchParams.get('state');
    const errorParam = searchParams.get('error');
    const errorDescription = searchParams.get('error_description');

    if (errorParam) {
      console.error('OAuth error:', errorParam, errorDescription);
      return;
    }

    if (code && state) {
      handleCallback(code, state);
    }
  }, [searchParams, handleCallback]);

  if (error) {
    return React.createElement(
      'div',
      { style: styles.container },
      React.createElement('div', { style: styles.card }, React.createElement('div', { style: styles.error }, error)),
      React.createElement(
        'button',
        {
          style: styles.button,
          onClick: () => (window.location.href = '/'),
        },
        'Return to Login'
      )
    );
  }

  return React.createElement(
    'div',
    { style: styles.loader },
    React.createElement('div', { style: styles.spinner }),
    React.createElement('p', { style: { color: '#666' } }, 'Completing sign in...')
  );
}

